import Publisher from"./publisher.model.js";import{ObjectId}from"mongodb";import{io}from"../socket/io.js";export default{createPublication:e=>new Promise((i,t)=>{const l=new Publisher({date:Date(),title:e.title,userPublicate:{name:e.userName},local:{localName:e.localName,id:e.localId},noveltie:e.idCategory||null,corte:e.IdCorte||null});l.save().then(e=>{i(e),io.emit("sendPublisher",e)}).catch(e=>t(e))}),getAllPublisher:()=>new Promise((e,i)=>{Publisher.find({}).exec((t,l)=>{t&&i(t),e(l)})}),getPublisherAndArticle:e=>new Promise((i,t)=>{Publisher.findOne({_id:e}).populate({path:"noveltie",populate:"fileNoveltie"}).populate({path:"corte"}).exec((e,l)=>{e&&t(e),i(l)})}),getPublisherPaginate:(e,i)=>new Promise((t,l)=>{Publisher.find({}).sort({$natural:-1}).skip(e*i).limit(i).exec((e,i)=>{e&&l(e),t(i)})}),searchPublisher:(e,i,t)=>new Promise((l,r)=>{Publisher.find({$text:{$search:e}}).sort({createdAt:-1}).skip(i*t).limit(t).limit(10).exec((e,i)=>{e&&r(e),l(i)})})};